mapper.select:
SELECT finance_seq AS financeSeq, user_seq AS userSeq, store_seq AS storeSeq, type, amount, category, description, target_date AS targetDate, created_at AS createdAt FROM finances WHERE store_seq = ( CASE WHEN #{storeSeq} IS NOT NULL AND #{storeSeq} != 0 THEN #{storeSeq} ELSE (SELECT store_seq FROM stores WHERE user_seq = #{userSeq} ORDER BY store_seq ASC LIMIT 1) END )
AND target_date >= #{startDate}
AND target_date <= #{endDate}
AND type = #{type}
ORDER BY target_date DESC, finance_seq DESC
